function Message({ sender, text }) {
    const isUser = sender === "user";

    return (
        <div
            style={{
                display: "flex",
                justifyContent: isUser ? "flex-end" : "flex-start",
                marginBottom: "12px",
            }}
        >
            <div
                style={{
                    maxWidth: "70%",
                    padding: "12px 16px",
                    borderRadius: "12px",
                    backgroundColor: isUser ? "#4f46e5" : "#e5e7eb",
                    color: isUser ? "#fff" : "#000",
                    whiteSpace: "pre-wrap",
                }}
            >
                {text}
            </div>
        </div>
    );
}

export default Message;
